import './App.css';
import React, { useRef, useEffect, useState } from 'react';
import DeckGL from 'deck.gl';
import {LineLayer, ScatterplotLayer} from '@deck.gl/layers';
import {Map, StaticMap, MapContext, NavigationControl} from 'react-map-gl';


import 'mapbox-gl/dist/mapbox-gl.css';
import './index.css';

//import  customData  from './ontario_place_tree_species.geojson';


const MAPBOX_ACCESS_TOKEN = 'pk.eyJ1IjoidmVudG9saW5lIiwiYSI6ImNsbjBzYnY3eDFzb24yc3F2OW1hZ3V2YWoifQ.pelghd1_gDY9DeAYv3rrAw';
const DATA_URL ="./ontario_place_tree_species.geojson";
const  dataTrees = require("./ontario_place_tree_species.geojson");// customData;
console.log(dataTrees.geometry)



// Viewport settings
const INITIAL_VIEW_STATE = {
  longitude: -79.418,  //-122.41669,
  latitude: 43.628077, //37.7853,
  zoom: 17,
  pitch: 0,
  bearing: 0
};


// Data to be used by the LineLayer
const data = [{
  "type" : "Feature", 
  "id" : 16, 
  "geometry" : 
  {
    "type" : "Point", 
    "coordinates" : [
      -79.4141775308424, 43.6284671429259
    ]
  }, 
  "properties" : {
    "OBJECTID" : 16, 
    "INW_DATE" : 1633637497452, 
    "ID_BLOCK" : "OP", 
    "LOCATION" : "ut", 
    "SP_CODE" : "pice-gla", 
    "Cultivar" : null, 
    "STEMNO" : 1, 
    "DBH" : 25.2, 
    "SURF_H" : 0, 
    "CANOPYW" : 4.6, 
    "HBASE" : 4.2, 
    "HTOTAL" : 10.8, 
    "RED_HEIG" : 0, 
    "CAB_BR" : "n", 
    "CONF_WIRES" : "n", 
    "CONF_SIDEW" : "n", 
    "CONF_STRUC" : "n", 
    "CONF_TREE" : "e", 
    "CONF_TRAF" : "n", 
    "FLAG" : null, 
    "GlobalID" : "26fc0918-8737-42a6-ae79-ff1991f88f51", 
    "CreationDate" : 1633638419336, 
    "Creator" : "NWCrew3", 
    "EditDate" : 1643385302520, 
    "Editor" : "forests.settledlandscapes_utoronto", 
    "CrownRad" : 2.3
  }
}, 
{
  "type" : "Feature", 
  "id" : 17, 
  "geometry" : 
  {
    "type" : "Point", 
    "coordinates" : [
      -79.4141381729548, 43.6284033562954
    ]
  }, 
  "properties" : {
    "OBJECTID" : 17, 
    "INW_DATE" : 1633638436462, 
    "ID_BLOCK" : "OP", 
    "LOCATION" : "ut", 
    "SP_CODE" : "aila-alt", 
    "Cultivar" : null, 
    "STEMNO" : 2, 
    "DBH" : 28.5, 
    "SURF_H" : 20, 
    "CANOPYW" : 8.4, 
    "HBASE" : 1.9, 
    "HTOTAL" : 14.5, 
    "RED_HEIG" : 0, 
    "CAB_BR" : "n", 
    "CONF_WIRES" : "n", 
    "CONF_SIDEW" : "n", 
    "CONF_STRUC" : "n", 
    "CONF_TREE" : "e", 
    "CONF_TRAF" : "n", 
    "FLAG" : null, 
    "GlobalID" : "bc0989a9-70cc-4974-8288-b1576d485bab", 
    "CreationDate" : 1633638657588, 
    "Creator" : "NWCrew3", 
    "EditDate" : 1643385302520, 
    "Editor" : "forests.settledlandscapes_utoronto", 
    "CrownRad" : 4.2
  }
}];


function App() {




  const layers = [
    new LineLayer({id: 'line-layer', data}), 

    new ScatterplotLayer({
      id: "trees",
      data: dataTrees ,


      getPosition:  d => d.geometry.coordinates,
      getRadius:d => d.properties.CrownRad,
      getFillColor: [255, 0, 0]
    })



  ];

  return (
      <DeckGL
    initialViewState={INITIAL_VIEW_STATE}
    controller={true}
    layers={layers} 
    >
          <Map 
          mapboxAccessToken={MAPBOX_ACCESS_TOKEN} 
          mapStyle="mapbox://styles/mapbox/light-v11"
          />
</DeckGL>   

  );
}

export default App;
